import pandas as pd

# DATASET PATH
dataset_path = "./data/fruit_to_emoji/playground/balanced_fruit_data.csv"

# Load the dataset
df = pd.read_csv(dataset_path)

# Define color thresholds for each fruit
color_thresholds = {
    'orange': {'Red_min': 0.5, 'Green_max': 0.35},
    'apple': {'Red_max': 0.6, 'Green_max': 0.4, 'Blue_max': 0.2},
    # Add more fruits and their respective thresholds as needed
}

# Apply color thresholding
def apply_color_threshold(row):
    fruit = row['Fruit']
    red, green, blue = row['Red'], row['Green'], row['Blue']

    if fruit in color_thresholds:
        thresholds = color_thresholds[fruit]
        for key, value in thresholds.items():
            if key.startswith('Red'):
                if not (eval(f"{key.split('_')[1]} {value}")):
                    return False
            elif key.startswith('Green'):
                if not (eval(f"{key.split('_')[1]} {value}")):
                    return False
            elif key.startswith('Blue'):
                if not (eval(f"{key.split('_')[1]} {value}")):
                    return False
    return True

# Filter the dataset based on color thresholds
filtered_df = df[df.apply(apply_color_threshold, axis=1)]

# Save the filtered dataset to a new CSV file
output_path = "./data/fruit_to_emoji/playground/color_thresholded_fruit_data.csv"
filtered_df.to_csv(output_path, index=False)
